// ── AUTH ──────────────────────────────────────────────────────────────────────
function openAuth(mode){authMode=mode;switchAuthTab(mode);document.getElementById("authModal").classList.add("open");}
function closeAuth(){document.getElementById("authModal").classList.remove("open");}
function switchAuthTab(mode){
  authMode=mode;
  document.getElementById("authTitle").textContent=mode==="signin"?"Welcome Back":"Create Account";
  document.getElementById("authBtn").textContent=mode==="signin"?"Sign In":"Create Account";
  document.getElementById("signinTab").className="auth-tab"+(mode==="signin"?" active":"");
  document.getElementById("signupTab").className="auth-tab"+(mode==="signup"?" active":"");
  document.getElementById("signupNameRow").style.display=mode==="signup"?"block":"none";
  document.getElementById("authHint").style.display=mode==="signin"?"block":"none";
}
function doAuth(){
  const email=document.getElementById("authEmail").value.trim();
  const name=document.getElementById("authName")?.value.trim();
  if(!email){showToast("Please enter email","#ef4444");return;}
  if(authMode==="signin"){
    const u=MOCK_USERS.find(x=>x.email===email);
    if(u)loginUser(u);else showToast("User not found. Try john@example.com","#ef4444");
  } else {
    loginUser({id:Date.now(),name:name||email.split("@")[0],email,role:"user",enrolled:[],progress:{}});
  }
}
function loginUser(u){
  currentUser=u;enrolledIds=[...u.enrolled];userProgress={...u.progress};
  document.getElementById("guestAuth").style.display="none";
  document.getElementById("userAuth").style.display="block";
  document.getElementById("userInitial").textContent=u.name[0].toUpperCase();
  document.getElementById("userName").textContent=u.name.split(" ")[0];
  document.getElementById("adminBtn").style.display=u.role==="admin"?"block":"none";
  closeAuth();showToast(`Welcome, ${u.name}! 👋`);updateCartBadge();
}
function signOut(){
  currentUser=null;enrolledIds=[];userProgress={};cart=[];
  document.getElementById("guestAuth").style.display="flex";
  document.getElementById("userAuth").style.display="none";
  updateCartBadge();showPage("home");closeDropdown();showToast("Signed out successfully");
}
function toggleDropdown(){document.getElementById("userDropdown").classList.toggle("open");}
function closeDropdown(){document.getElementById("userDropdown").classList.remove("open");}
document.addEventListener("click",e=>{if(!e.target.closest(".user-menu"))closeDropdown();});

// ── CART ──────────────────────────────────────────────────────────────────────
function addToCart(id,type,price,title,thumb,instructor){
  if(!currentUser){openAuth("signin");return;}
  if(enrolledIds.includes(id)){showToast("Already enrolled!","#f59e0b");return;}
  if(cart.find(c=>c.cartId===id+type)){showToast("Already in cart!","#f59e0b");return;}
  cart.push({cartId:id+type,id,type,price,title,thumb,instructor});
  updateCartBadge();showToast(`"${title}" (${type}) added to cart! 🛒`);
}
function addFlatToCart(course){
  if(!currentUser){openAuth("signin");return;}
  if(enrolledIds.includes(course.id)){showToast("Already enrolled!","#f59e0b");return;}
  if(cart.find(c=>c.id===course.id&&!c.productCourse)){showToast("Already in cart!","#f59e0b");return;}
  cart.push({cartId:"flat"+course.id,id:course.id,type:course.type,price:course.price,title:course.title,thumb:course.thumb,instructor:course.instructor,productCourse:false});
  updateCartBadge();showToast(`"${course.title}" added to cart! 🛒`);
}
function removeFromCart(cartId){cart=cart.filter(c=>c.cartId!==cartId);updateCartBadge();renderCart();}
function updateCartBadge(){
  const b=document.getElementById("cartBadge");
  b.textContent=cart.length;b.style.display=cart.length>0?"flex":"none";
}

function doSearch(v){
  if(v){showPage("video");}
}

// ── TRAINING PROGRAM ──────────────────────────────────────────────────────────
function renderTraining(){
  const el=document.getElementById("tpContent");
  if(tpView==="products"){
    el.innerHTML=`<div class="product-grid">${PRODUCTS.map(p=>`
      <div class="product-card" onclick="openProductCourses('${p.id}')">
        <div class="product-icon">${p.icon}</div>
        <div class="product-name">${p.name}</div>
        <div class="product-desc">${p.desc}</div>
        <span class="product-count">${p.courses.length} courses</span>
      </div>`).join("")}</div>`;
  } else {
    // show courses for tpProduct
    const p=PRODUCTS.find(x=>x.id===tpProduct);
    const html=p.courses.map(c=>{
      const chosenType=courseTypeChoice[c.id]||"onsite";
      const price=chosenType==="onsite"?c.priceOnsite:c.priceOnline;
      const enrolled=enrolledIds.includes(c.id);
      return `<div class="tp-course-row">
        <div class="tp-course-inner">
          <div class="tp-thumb">${c.thumb}</div>
          <div class="tp-info">
            <div class="tp-title">${c.title}</div>
            <div class="tp-meta">${c.instructor} · ${c.hours} hrs · ${c.level} · ${c.duration}</div>
            <div style="color:#f59e0b;font-size:12px;margin-top:2px">${stars(c.rating)} <span style="color:var(--text2)">(${c.students.toLocaleString()})</span></div>
          </div>
          <!-- type toggle -->
          <div class="type-toggle" id="tt-${c.id}">
            <button class="sel-onsite${chosenType==="onsite"?" selected":""}" onclick="setTPType('${c.id}','onsite');event.stopPropagation()">🏫 Onsite</button>
            <button class="sel-online${chosenType==="online"?" selected":""}" onclick="setTPType('${c.id}','online');event.stopPropagation()">🎬 Online</button>
          </div>
          <div class="tp-price" id="tpPrice-${c.id}">฿${fmt(price)}</div>
          <div class="tp-actions">
            <button class="btn-outline" style="padding:7px 13px;font-size:12px;border-radius:8px" onclick="openTPDetail('${p.id}','${c.id}')">Details</button>
            ${enrolled
              ?`<button style="padding:7px 13px;border-radius:8px;border:none;background:#d1fae5;color:#065f46;font-size:12px;font-weight:500;cursor:default">✓ Enrolled</button>`
              :`<button class="btn-primary" style="padding:7px 13px;font-size:12px;border-radius:8px" onclick="addToCart('${c.id}','${courseTypeChoice[c.id]||"onsite"}',${price},'${c.title.replace(/'/g,"\\'")}','${c.thumb}','${c.instructor}');event.stopPropagation()">Add to Cart</button>`}
          </div>
        </div>
      </div>`;
    }).join("");
    el.innerHTML=`<div class="breadcrumb">
      <span class="bc-link" onclick="tpView='products';renderTraining()">Training Program</span>
      <span class="bc-sep">›</span>
      <span style="color:var(--text)">${p.icon} ${p.name}</span>
    </div>
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:22px;flex-wrap:wrap">
      <div style="font-size:42px">${p.icon}</div>
      <div>
        <div style="font-weight:700;font-size:22px">${p.name}</div>
        <div style="font-size:13px;color:var(--text2)">${p.courses.length} courses · ${p.desc}</div>
      </div>
    </div>
    <div class="tp-course-list">${html}</div>`;
  }
}
function openProductCourses(pid){
  tpView="courses";tpProduct=pid;renderTraining();window.scrollTo(0,0);
}
function setTPType(cid,type){
  courseTypeChoice[cid]=type;
  // update toggle buttons
  const tt=document.getElementById("tt-"+cid);
  if(tt){
    tt.querySelectorAll("button").forEach(b=>{
      if(b.classList.contains("sel-"+type))b.classList.add("selected");
      else b.classList.remove("selected");
    });
  }
  // update price
  const p=PRODUCTS.find(x=>x.id===tpProduct);
  const c=p&&p.courses.find(x=>x.id===cid);
  if(c){
    const price=type==="onsite"?c.priceOnsite:c.priceOnline;
    const priceEl=document.getElementById("tpPrice-"+cid);
    if(priceEl)priceEl.textContent="฿"+fmt(price);
  }
}
function openTPDetail(pid,cid){
