      ${[...adminCourses].sort((a,b)=>b.students-a.students).slice(0,5).map((c,i)=>`
        <div style="display:flex;align-items:center;gap:9px;padding:9px 0;${i<4?"border-bottom:1px solid var(--border)":""}">
          <span style="width:20px;height:20px;border-radius:50%;background:linear-gradient(135deg,var(--pink),var(--pink2));display:flex;align-items:center;justify-content:center;color:#fff;font-size:10px;font-weight:700;flex-shrink:0">${i+1}</span>
          <span style="font-size:16px">${c.thumb}</span>
          <span style="flex:1;font-size:13px;font-weight:500">${c.title}</span>
          <span style="font-size:12px;color:var(--text2)">${c.students} students</span>
          <span style="font-size:12px;font-weight:600;color:var(--pink)">฿${fmt(c.price*c.students)}</span>
        </div>`).join("")}
    </div>`;
  } else if(adminTab==="courses"){
    const formHTML=editingId?`<div class="edit-form">
      <div style="font-weight:600;font-size:15px;margin-bottom:13px">${editingId==="new"?"Add Course":"Edit Course"}</div>
      <div class="edit-grid">
        ${[["Course Title","etitle","text"],["Price (THB)","eprice","number"],["Instructor","einstructor","text"],["Thumbnail","ethumb","text"],["Hours","ehours","number"],["Duration","eduration","text"]].map(([l,id])=>`<div><label class="edit-label">${l}</label><input class="edit-input" id="${id}" /></div>`).join("")}
        ${[["etype",["online","onsite"]],["elevel",["Beginner","Intermediate","Advanced"]],["ecat",["Cloud","Data","DevOps","Web Dev","Security","AI/ML"]]].map(([id,opts])=>`<div><label class="edit-label" style="text-transform:capitalize">${id.slice(1)}</label><select class="edit-input" id="${id}">${opts.map(o=>`<option>${o}</option>`).join("")}</select></div>`).join("")}
      </div>
      <div><label class="edit-label">Description</label><textarea class="edit-input" id="edesc" rows="3" style="width:100%;resize:vertical"></textarea></div>
      <div style="display:flex;gap:9px;margin-top:13px">
        <button class="btn-primary" style="padding:9px 20px;border-radius:8px" onclick="saveAdminCourse()">Save Changes</button>
        <button class="btn-outline" style="padding:9px 20px;border-radius:8px" onclick="editingId=null;renderAdmin()">Cancel</button>
      </div>
    </div>`:"";
    content=`<button class="btn-primary" style="margin-bottom:13px;padding:9px 18px;border-radius:10px" onclick="startEditCourse(null)">+ Add Course</button>
    ${formHTML}
    ${adminCourses.map(c=>`<div class="course-row">
      <span style="font-size:22px">${c.thumb}</span>
      <div style="flex:1;min-width:110px"><div style="font-weight:500;font-size:13px">${c.title}</div><div style="font-size:11px;color:var(--text2)">${c.instructor} · ${c.students} students</div></div>
      <span style="font-weight:700;color:var(--pink);font-size:13px">฿${fmt(c.price)}</span>
      <div style="display:flex;gap:7px">
        <button onclick="startEditCourse(${c.id})" style="padding:5px 12px;border-radius:7px;border:1px solid var(--border);background:none;font-size:11px;cursor:pointer">Edit</button>
        <button onclick="deleteAdminCourse(${c.id})" style="padding:5px 12px;border-radius:7px;border:1px solid #fecaca;background:#fef2f2;color:#dc2626;font-size:11px;cursor:pointer">🗑</button>
      </div>
    </div>`).join("")}`;
  } else {
    content=MOCK_USERS.map(u=>`<div class="user-row">
      <div style="width:36px;height:36px;border-radius:50%;background:linear-gradient(135deg,var(--pink),var(--pink2));display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:14px">${u.name[0]}</div>
      <div style="flex:1"><div style="font-weight:500;font-size:14px">${u.name}</div><div style="font-size:12px;color:var(--text2)">${u.email}</div></div>
      <span class="role-badge ${u.role==="admin"?"role-admin":"role-user"}">${u.role}</span>
      <span style="font-size:12px;color:var(--text2)">${u.enrolled.length} courses</span>
    </div>`).join("");
  }
  el.innerHTML=`<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;flex-wrap:wrap;gap:9px"><div style="font-size:24px;font-weight:700">Admin Dashboard</div></div>${tabsHTML}${content}`;
  if(editingId){
    const c=editingId==="new"?null:adminCourses.find(x=>x.id===editingId);
    if(c){["etitle","eprice","einstructor","ethumb","ehours","eduration"].forEach((id,i)=>{const keys=["title","price","instructor","thumb","hours","duration"];const el2=document.getElementById(id);if(el2)el2.value=c[keys[i]]||"";});
      ["etype","elevel","ecat"].forEach((id,i)=>{const keys=["type","level","category"];const el2=document.getElementById(id);if(el2)el2.value=c[keys[i]]||"";});
      const ed=document.getElementById("edesc");if(ed)ed.value=c.desc||"";}
  }
}
function setAdminTab(t){adminTab=t;renderAdmin();}
function startEditCourse(id){editingId=id||"new";renderAdmin();}
function saveAdminCourse(){
  const g=id=>document.getElementById(id)?.value;
  const obj={title:g("etitle"),price:+g("eprice"),instructor:g("einstructor"),thumb:g("ethumb"),hours:+g("ehours"),duration:g("eduration"),type:g("etype"),level:g("elevel"),category:g("ecat"),desc:g("edesc")};
  if(editingId==="new")adminCourses.push({...obj,id:Date.now(),rating:4.5,students:0,seats:null,tags:[],vid:""});
  else adminCourses=adminCourses.map(c=>c.id===editingId?{...c,...obj}:c);
  editingId=null;showToast("Changes saved! ✅");renderAdmin();
}
function deleteAdminCourse(id){if(confirm("Delete this course?")){adminCourses=adminCourses.filter(c=>c.id!==id);showToast("Course deleted","#ef4444");renderAdmin();}}

// ── CONTACT ───────────────────────────────────────────────────────────────────
function sendContact(){
  const n=document.getElementById("cName").value.trim();
  const e=document.getElementById("cEmail").value.trim();
  const m=document.getElementById("cMsg").value.trim();
  if(!n||!e||!m){showToast("Please fill all required fields","#ef4444");return;}
  document.getElementById("contactForm").style.display="none";
  document.getElementById("contactSent").style.display="block";
  showToast("Message sent! We'll reply within 24h 📬");
}

// ── INIT ──────────────────────────────────────────────────────────────────────
renderFeatured();

history.css:
*{box-sizing:border-box;margin:0;padding:0}
:root{
  --pink:#ec4899;--pink2:#f43f5e;--pink-light:#fce7f3;--purple-light:#ede9fe;
  --text:#1a1a2e;--text2:#6b7280;--border:#e5e7eb;--bg:#f9fafb;--white:#fff;
  --radius:12px;--radius-lg:16px;--shadow:0 4px 24px rgba(236,72,153,.1);
}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:var(--bg);color:var(--text);min-height:100vh}
button{font-family:inherit;cursor:pointer}
input,select,textarea{font-family:inherit}

/* NAV */
nav{background:var(--white);border-bottom:1px solid var(--border);position:sticky;top:0;z-index:200}
.nav-inner{max-width:1200px;margin:0 auto;padding:0 16px;display:flex;align-items:center;gap:10px;height:62px;flex-wrap:nowrap}
.logo{display:flex;align-items:center;gap:7px;border:none;background:none;cursor:pointer;flex-shrink:0}
.logo-icon{width:34px;height:34px;border-radius:9px;background:linear-gradient(135deg,var(--pink),var(--pink2));display:flex;align-items:center;justify-content:center;font-size:17px;font-weight:800;color:#fff}
.logo-text{font-size:18px;font-weight:700;background:linear-gradient(135deg,var(--pink),var(--pink2));-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.logo-sub{font-size:18px;color:var(--text)}
.nav-links{display:flex;gap:1px;align-items:center}
.nav-btn{padding:5px 9px;border-radius:7px;border:none;background:none;color:var(--text2);font-size:12.5px;cursor:pointer;transition:.15s;white-space:nowrap}
.nav-btn:hover,.nav-btn.active{background:var(--pink-light);color:var(--pink);font-weight:600}
.nav-right{display:flex;align-items:center;gap:8px;flex-shrink:0;margin-left:auto}
.nav-search{position:relative}
.nav-search input{padding:6px 12px 6px 30px;border-radius:8px;border:1px solid var(--border);background:#f3f4f6;font-size:12px;width:140px;outline:none}
.nav-search span{position:absolute;left:9px;top:50%;transform:translateY(-50%);font-size:12px;pointer-events:none}
.lang-btn{padding:4px 9px;border-radius:7px;border:1px solid var(--border);background:none;font-size:12px;color:var(--text2)}
.cart-btn{position:relative;padding:5px 9px;border-radius:7px;border:1px solid var(--border);background:none;font-size:17px}
.cart-badge{position:absolute;top:-4px;right:-4px;background:var(--pink);color:#fff;width:16px;height:16px;border-radius:50%;font-size:9px;display:flex;align-items:center;justify-content:center;font-weight:700}
.btn-primary{padding:7px 15px;border-radius:8px;border:none;background:linear-gradient(135deg,var(--pink),var(--pink2));color:#fff;font-size:12.5px;font-weight:500;transition:.15s}
.btn-outline{padding:7px 15px;border-radius:8px;border:1.5px solid var(--pink);background:none;color:var(--pink);font-size:12.5px;font-weight:500;transition:.15s}
.btn-primary:hover{opacity:.9;transform:translateY(-1px)}
.btn-outline:hover{background:var(--pink-light)}
.user-menu{position:relative}
.user-avatar{width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,var(--pink),var(--pink2));display:inline-flex;align-items:center;justify-content:center;color:#fff;font-size:11px;font-weight:700}
.dropdown{display:none;position:absolute;right:0;top:calc(100% + 7px);background:var(--white);border:1px solid var(--border);border-radius:12px;padding:6px;min-width:185px;box-shadow:0 8px 24px rgba(0,0,0,.08)}
.dropdown.open{display:block}
.dropdown button{width:100%;padding:7px 11px;border-radius:8px;border:none;background:none;text-align:left;font-size:13px;color:var(--text);transition:.12s}
.dropdown button:hover{background:var(--bg)}
.dropdown .sign-out{color:#ef4444}

/* PAGES */
.page{display:none}.page.active{display:block}
main{min-height:calc(100vh - 62px)}

/* HERO */
.hero{background:linear-gradient(135deg,#fdf2f8 0%,#f5f3ff 50%,#eff6ff 100%);padding:80px 24px 60px;text-align:center;overflow:hidden}
.hero-badge{display:inline-block;padding:4px 15px;border-radius:20px;background:rgba(236,72,153,.1);color:#be185d;font-size:13px;font-weight:500;margin-bottom:18px;border:1px solid rgba(236,72,153,.2)}
.hero h1{font-size:clamp(28px,6vw,54px);font-weight:800;line-height:1.1;margin-bottom:14px}
.hero h1 span{background:linear-gradient(135deg,var(--pink),var(--pink2));-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.hero p{font-size:17px;color:var(--text2);margin-bottom:30px;max-width:580px;margin-left:auto;margin-right:auto;line-height:1.7}
.hero-btns{display:flex;gap:12px;justify-content:center;flex-wrap:wrap}
.hero-btns .btn-hero{padding:13px 30px;border-radius:12px;font-size:15px;font-weight:600}
.stats{background:var(--white);border-bottom:1px solid var(--border)}
.stats-inner{max-width:960px;margin:0 auto;padding:28px 24px;display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:20px;text-align:center}
.stat-num{font-size:26px;font-weight:700;color:var(--pink)}
.stat-label{font-size:12px;color:var(--text2);margin-top:2px}
.section{max-width:1100px;margin:0 auto;padding:50px 24px 36px}
.section-title{font-size:26px;font-weight:700;margin-bottom:6px}
.section-sub{color:var(--text2);margin-bottom:24px}
.card-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:18px}
.course-card{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);overflow:hidden;transition:transform .18s,box-shadow .18s;cursor:pointer}
.course-card:hover{transform:translateY(-4px);box-shadow:var(--shadow)}
.card-thumb{height:130px;background:linear-gradient(135deg,var(--pink-light),var(--purple-light));display:flex;align-items:center;justify-content:center;font-size:48px}
.card-body{padding:14px}
.card-badges{display:flex;gap:5px;flex-wrap:wrap;margin-bottom:7px}
.badge{font-size:11px;padding:2px 8px;border-radius:20px;font-weight:500}
.badge-onsite{background:var(--pink-light);color:#be185d;border:1px solid #fbcfe8}
.badge-online{background:var(--purple-light);color:#6d28d9;border:1px solid #ddd6fe}
.badge-cat{background:#f3f4f6;color:var(--text2);border:1px solid var(--border)}
.card-title{font-weight:600;font-size:14px;margin-bottom:3px;line-height:1.35}
.card-meta{font-size:11px;color:var(--text2);margin-bottom:5px}
.card-stars{color:#f59e0b;font-size:12px}
.card-stars span{color:var(--text2);font-weight:400}
.card-footer{display:flex;align-items:center;justify-content:space-between;margin-top:9px}
.card-price{font-weight:700;font-size:17px;color:var(--pink)}
.card-seats{font-size:11px;color:#f59e0b;font-weight:500}
.card-btns{display:flex;gap:7px;margin-top:10px}
.card-btns button{flex:1;padding:7px 0;border-radius:7px;font-size:12px;font-weight:500;border:none;cursor:pointer;transition:.15s}
.card-btn-outline{border:1px solid var(--pink)!important;color:var(--pink);background:none!important}
.card-btn-fill{background:linear-gradient(135deg,var(--pink),var(--pink2));color:#fff}
.card-btn-enrolled{background:#d1fae5;color:#065f46;cursor:default!important}

/* WHY */
.why{background:linear-gradient(135deg,#fdf2f8,#f5f3ff);padding:50px 24px}
.why-inner{max-width:960px;margin:0 auto;text-align:center}
.why-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:18px;margin-top:24px}
.why-card{background:var(--white);border-radius:var(--radius-lg);padding:22px;border:1px solid var(--border);text-align:center}
.why-icon{font-size:34px;margin-bottom:10px}
.why-title{font-weight:600;font-size:15px;margin-bottom:5px}
.why-sub{font-size:12px;color:var(--text2);line-height:1.6}
.cta-banner{background:linear-gradient(135deg,var(--pink),var(--pink2));padding:52px 24px;text-align:center;color:#fff}
.cta-banner h2{font-size:28px;font-weight:700;margin-bottom:8px}
.cta-banner p{font-size:15px;opacity:.88;margin-bottom:24px}
.cta-banner button{padding:13px 32px;border-radius:12px;border:2px solid #fff;background:#fff;color:var(--pink);font-weight:700;font-size:15px;cursor:pointer}
.filters{display:flex;gap:10px;margin-bottom:22px;flex-wrap:wrap}
.filters input,.filters select{padding:8px 13px;border-radius:10px;border:1px solid var(--border);background:var(--white);font-size:13px;outline:none}
.filters input{flex:1;min-width:150px}

/* ── TRAINING PROGRAM (Product Categories) ── */
.tp-header{background:linear-gradient(135deg,#fdf2f8,#f5f3ff);padding:48px 24px 36px;text-align:center}
.tp-header h1{font-size:clamp(24px,4vw,34px);font-weight:700;margin-bottom:8px}
.tp-header p{color:var(--text2);font-size:15px}
.tp-section{max-width:1100px;margin:0 auto;padding:36px 24px 48px}
/* Product card grid */
.product-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:18px;margin-bottom:12px}
.product-card{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);padding:24px 16px;text-align:center;cursor:pointer;transition:transform .18s,box-shadow .18s,border-color .18s}
.product-card:hover{transform:translateY(-4px);box-shadow:var(--shadow);border-color:var(--pink)}
.product-icon{font-size:44px;margin-bottom:10px}
.product-name{font-weight:700;font-size:15px;margin-bottom:4px}
.product-desc{font-size:12px;color:var(--text2);line-height:1.5}
.product-count{display:inline-block;margin-top:8px;padding:2px 10px;border-radius:20px;background:var(--pink-light);color:#be185d;font-size:11px;font-weight:600}
/* Breadcrumb */
.breadcrumb{display:flex;align-items:center;gap:6px;font-size:13px;color:var(--text2);margin-bottom:20px;flex-wrap:wrap}
.breadcrumb .bc-link{cursor:pointer;color:var(--pink);font-weight:500}
.breadcrumb .bc-link:hover{text-decoration:underline}
.breadcrumb .bc-sep{color:var(--border)}
/* Sub-course list */
.tp-course-list{display:grid;gap:14px}
.tp-course-row{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);overflow:hidden;transition:box-shadow .18s}
.tp-course-row:hover{box-shadow:var(--shadow)}
.tp-course-inner{display:flex;align-items:center;gap:14px;padding:16px 18px;flex-wrap:wrap}
.tp-thumb{width:54px;height:54px;border-radius:12px;background:linear-gradient(135deg,var(--pink-light),var(--purple-light));display:flex;align-items:center;justify-content:center;font-size:26px;flex-shrink:0}
.tp-info{flex:1;min-width:160px}
.tp-title{font-weight:600;font-size:15px;margin-bottom:3px}
.tp-meta{font-size:12px;color:var(--text2)}
/* Type toggle */
.type-toggle{display:flex;gap:0;background:#f3f4f6;border-radius:8px;padding:3px;flex-shrink:0}
.type-toggle button{padding:5px 13px;border-radius:6px;border:none;font-size:12px;font-weight:500;cursor:pointer;transition:.15s;background:none;color:var(--text2)}
.type-toggle button.selected{background:var(--white);color:var(--text);box-shadow:0 1px 4px rgba(0,0,0,.08)}
.type-toggle button.sel-onsite.selected{color:#be185d}
.type-toggle button.sel-online.selected{color:#6d28d9}
.tp-price{font-weight:700;font-size:17px;color:var(--pink);flex-shrink:0;min-width:90px;text-align:right}
.tp-actions{display:flex;gap:8px;flex-shrink:0}

/* PROMO */
.promo-card{background:var(--white);border:1px solid var(--border);border-radius:20px;overflow:hidden;margin-bottom:20px}
.promo-header{padding:22px 26px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;color:#fff}
.promo-pct{font-size:48px;font-weight:900;line-height:1}
.promo-body{padding:16px 26px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px}
.promo-code{padding:7px 14px;border-radius:8px;background:#f3f4f6;font-family:monospace;font-weight:600;font-size:13px;border:1px dashed #d1d5db}
.about-hero{background:linear-gradient(135deg,#fdf2f8,#f5f3ff);padding:52px 24px;text-align:center}
.about-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(270px,1fr));gap:22px;margin-bottom:44px}
.info-card{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);padding:22px}
.team-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:16px}
.team-card{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);padding:18px 12px;text-align:center}
.team-avatar{font-size:44px;margin-bottom:8px}
.contact-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:26px}
.form-label{font-size:13px;font-weight:500;color:var(--text2);display:block;margin-bottom:3px}
.form-input{width:100%;padding:9px 13px;border-radius:10px;border:1px solid var(--border);font-size:14px;outline:none;transition:.15s;margin-bottom:13px}
.form-input:focus{border-color:var(--pink)}
textarea.form-input{resize:vertical;min-height:110px}
.contact-info{display:flex;flex-direction:column;gap:11px}
.contact-item{background:var(--white);border:1px solid var(--border);border-radius:12px;padding:13px 17px;display:flex;align-items:center;gap:11px;font-size:14px}
.detail-grid{display:grid;grid-template-columns:1fr 310px;gap:26px;align-items:start}
@media(max-width:768px){.detail-grid{grid-template-columns:1fr}}
.video-box{border-radius:16px;overflow:hidden;background:#1e1b4b;aspect-ratio:16/9;display:flex;align-items:center;justify-content:center;cursor:pointer;margin-bottom:22px;position:relative}
.play-overlay{display:flex;flex-direction:column;align-items:center;gap:10px;width:100%;height:100%;justify-content:center}
.play-btn{width:60px;height:60px;border-radius:50%;background:rgba(236,72,153,.9);display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;border:none;cursor:pointer}
.detail-sidebar{background:var(--white);border:1px solid var(--border);border-radius:20px;padding:22px;box-shadow:var(--shadow);position:sticky;top:76px}
.includes-grid{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:18px}
.includes-item{display:flex;align-items:center;gap:7px;font-size:13px}
.cart-grid{display:grid;grid-template-columns:1fr 295px;gap:22px;align-items:start}
@media(max-width:700px){.cart-grid{grid-template-columns:1fr}}
.cart-item{background:var(--white);border:1px solid var(--border);border-radius:13px;padding:14px;display:flex;gap:13px;align-items:center;margin-bottom:11px}
.cart-thumb{width:56px;height:56px;border-radius:10px;background:linear-gradient(135deg,var(--pink-light),var(--purple-light));display:flex;align-items:center;justify-content:center;font-size:26px;flex-shrink:0}
.summary-box{background:var(--white);border:1px solid var(--border);border-radius:16px;padding:20px}
.summary-row{display:flex;justify-content:space-between;font-size:14px;padding:4px 0;color:var(--text2)}
.summary-total{display:flex;justify-content:space-between;font-weight:700;font-size:17px;border-top:1px solid var(--border);padding-top:11px;margin-top:7px}
.promo-row{display:flex;gap:7px;margin:10px 0}
.promo-row input{flex:1;padding:8px 11px;border-radius:8px;border:1px solid var(--border);font-size:13px;outline:none}
.step-indicator{display:flex;gap:0;margin-bottom:22px;background:#f3f4f6;border-radius:10px;padding:3px}
.step-indicator button{flex:1;padding:7px;border-radius:8px;border:none;font-size:13px;cursor:pointer;transition:.15s}
.step-indicator button.active-step{background:var(--white);font-weight:600;color:var(--text)}
.step-indicator button:not(.active-step){background:none;color:var(--text2)}
.dash-welcome{display:flex;align-items:center;gap:14px;background:linear-gradient(135deg,#fdf2f8,#f5f3ff);border-radius:16px;padding:20px;margin-bottom:24px}
.dash-avatar{width:52px;height:52px;border-radius:50%;background:linear-gradient(135deg,var(--pink),var(--pink2));display:flex;align-items:center;justify-content:center;color:#fff;font-size:20px;font-weight:700;flex-shrink:0}
.prog-bar{height:6px;background:#e5e7eb;border-radius:3px;overflow:hidden}
.prog-fill{height:100%;background:linear-gradient(90deg,var(--pink),var(--pink2));border-radius:3px;transition:width .4s}
.prog-fill.complete{background:linear-gradient(90deg,#10b981,#059669)}
.admin-tabs{display:flex;gap:7px;margin-bottom:22px;flex-wrap:wrap}
.admin-tab{padding:7px 16px;border-radius:8px;border:1px solid var(--border);background:none;font-size:13px;cursor:pointer;transition:.15s;text-transform:capitalize}
.admin-tab.active{border-color:var(--pink);background:linear-gradient(135deg,var(--pink),var(--pink2));color:#fff;font-weight:600}
.admin-stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:13px;margin-bottom:24px}
.admin-stat{background:var(--white);border:1px solid var(--border);border-radius:13px;padding:16px 18px}
.admin-stat-num{font-size:24px;font-weight:700;color:var(--pink)}
.admin-stat-label{font-size:12px;color:var(--text2);margin-top:2px}
.course-row{background:var(--white);border:1px solid var(--border);border-radius:12px;padding:11px 15px;display:flex;align-items:center;gap:11px;margin-bottom:9px;flex-wrap:wrap}
.edit-form{background:var(--white);border:2px solid var(--pink);border-radius:16px;padding:20px;margin-bottom:18px}
.edit-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:11px;margin-bottom:11px}
.edit-label{font-size:12px;color:var(--text2);display:block;margin-bottom:3px}
.edit-input{width:100%;padding:7px 11px;border-radius:8px;border:1px solid var(--border);font-size:13px;outline:none}
.user-row{background:var(--white);border:1px solid var(--border);border-radius:12px;padding:13px 17px;display:flex;align-items:center;gap:13px;margin-bottom:9px;flex-wrap:wrap}
.role-badge{padding:3px 9px;border-radius:20px;font-size:12px;font-weight:500}
.role-admin{background:var(--pink-light);color:#be185d}
.role-user{background:var(--purple-light);color:#6d28d9}
.modal-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);align-items:center;justify-content:center;z-index:500;padding:16px}
.modal-overlay.open{display:flex}
.modal-box{background:var(--white);border-radius:20px;padding:26px 22px;width:100%;max-width:390px;position:relative}
.modal-close{position:absolute;top:13px;right:14px;background:none;border:none;font-size:19px;color:var(--text2);cursor:pointer}
.auth-tabs{display:flex;gap:0;margin-bottom:16px;background:#f3f4f6;border-radius:10px;padding:3px}
.auth-tab{flex:1;padding:7px;border-radius:8px;border:none;font-size:13px;cursor:pointer;transition:.15s}
.auth-tab.active{background:var(--white);font-weight:600}
.auth-tab:not(.active){background:none;color:var(--text2)}
.auth-hint{font-size:12px;color:var(--text2);background:#f3f4f6;padding:7px 11px;border-radius:8px;margin-bottom:13px}
.toast{position:fixed;bottom:22px;right:22px;background:#10b981;color:#fff;padding:11px 18px;border-radius:12px;font-weight:500;z-index:9999;box-shadow:0 4px 20px rgba(16,185,129,.35);animation:slideUp .3s ease;max-width:300px}
@keyframes slideUp{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
.video-card{background:var(--white);border:1px solid var(--border);border-radius:var(--radius-lg);overflow:hidden}
.video-thumb{height:140px;background:linear-gradient(135deg,var(--pink-light),var(--purple-light));display:flex;align-items:center;justify-content:center;font-size:48px;position:relative;cursor:pointer}
.video-play-overlay{position:absolute;inset:0;background:rgba(0,0,0,.2);display:flex;align-items:center;justify-content:center;opacity:0;transition:.2s}
.video-thumb:hover .video-play-overlay{opacity:1}
.video-play-overlay button{padding:7px 18px;border-radius:20px;background:#fff;color:var(--pink);border:none;font-weight:600;cursor:pointer;font-size:13px}
footer{background:var(--white);border-top:1px solid var(--border);padding:36px 24px 18px;margin-top:56px}
.footer-inner{max-width:1200px;margin:0 auto}
.footer-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:24px;margin-bottom:24px}
.footer-link{font-size:13px;color:var(--text2);margin-bottom:5px;cursor:pointer}
.footer-link:hover{color:var(--pink)}
.footer-bottom{border-top:1px solid var(--border);padding-top:13px;display:flex;justify-content:space-between;flex-wrap:wrap;gap:5px;font-size:12px;color:var(--text2)}
.success-box{max-width:460px;margin:70px auto;text-align:center;padding:22px}
.success-icon{font-size:68px;margin-bottom:14px}
.empty-box{text-align:center;padding:56px 22px}
.empty-icon{font-size:56px;margin-bottom:11px}
.back-btn{display:inline-flex;align-items:center;gap:5px;padding:7px 14px;border-radius:8px;border:1px solid var(--border);background:none;color:var(--text2);cursor:pointer;margin-bottom:20px;font-size:13px}
@media(max-width:960px){
  .nav-links .nav-btn{font-size:11.5px;padding:4px 7px}
}
@media(max-width:700px){
  .detail-grid,.cart-grid{grid-template-columns:1fr}
  .nav-search input{width:110px}
}

