function setTPType(cid,type){
  courseTypeChoice[cid]=type;
  // update toggle buttons
  const tt=document.getElementById("tt-"+cid);
  if(tt){
    tt.querySelectorAll("button").forEach(b=>{
      if(b.classList.contains("sel-"+type))b.classList.add("selected");
      else b.classList.remove("selected");
    });
  }
  // update price
  const p=PRODUCTS.find(x=>x.id===tpProduct);
  const c=p&&p.courses.find(x=>x.id===cid);
  if(c){
    const price=type==="onsite"?c.priceOnsite:c.priceOnline;
    const priceEl=document.getElementById("tpPrice-"+cid);
    if(priceEl)priceEl.textContent="฿"+fmt(price);
  }
}
function openTPDetail(pid,cid){
  const p=PRODUCTS.find(x=>x.id===pid);
  const c=p&&p.courses.find(x=>x.id===cid);
  if(!c)return;
  const type=courseTypeChoice[c.id]||"onsite";
  const price=type==="onsite"?c.priceOnsite:c.priceOnline;
  // build a flat-course-like object for detail page
  activeCourse={
    id:c.id,title:c.title,category:p.name,type,price,
    duration:c.duration,hours:c.hours,level:c.level,
    instructor:c.instructor,rating:c.rating,students:c.students,
    thumb:c.thumb,desc:c.desc,vid:"",seats:null,
    priceOnsite:c.priceOnsite,priceOnline:c.priceOnline,
    _pid:pid,_tp:true
  };
  prevPage=currentPage;
  renderDetail();
  document.querySelectorAll(".page").forEach(el=>el.classList.remove("active"));
  document.getElementById("page-detail").classList.add("active");
  currentPage="detail";window.scrollTo(0,0);
}

