function showToast(msg,color="#10b981"){
  const t=document.getElementById("toast");
  t.textContent=msg;t.style.background=color;t.style.display="block";
  setTimeout(()=>t.style.display="none",3000);
}

function showPage(p,btn){
  if(p==="dashboard"&&!currentUser){openAuth("signin");return;}
  if(p==="admin"&&(!currentUser||currentUser.role!=="admin")){showToast("Admin access required","#ef4444");return;}
  prevPage=currentPage;
  document.querySelectorAll(".page").forEach(el=>el.classList.remove("active"));
  document.getElementById("page-"+p).classList.add("active");
  document.querySelectorAll(".nav-btn").forEach(b=>b.classList.remove("active"));
  if(btn)btn.classList.add("active");
  else{
    // auto-highlight nav button
    const map={home:0,training:1,video:2,promo:3,about:4,contact:5};
    const idx=map[p];
    if(idx!==undefined){document.querySelectorAll(".nav-btn")[idx].classList.add("active");}
  }
  currentPage=p;window.scrollTo(0,0);
  if(p==="training"){tpView="products";tpProduct=null;renderTraining();}
  if(p==="video")renderVideo();
  if(p==="promo")renderPromos();
  if(p==="cart")renderCart();
  if(p==="dashboard")renderDashboard();
  if(p==="admin")renderAdmin();
  if(p==="home")renderFeatured();
}
function goBack(){
  if(currentPage==="detail"){showPage(prevPage||"home");return;}
  if(tpView==="courses"){tpView="products";tpProduct=null;renderTraining();return;}
  showPage(prevPage||"home");
}

