          <div style="font-weight:600;font-size:15px">${c.instructor}</div>
          <div style="font-size:12px;color:var(--text2)">Senior Instructor</div>
          <div style="color:#f59e0b;font-size:12px">★★★★★ 4.9</div>
        </div>
      </div>
    </div>
    <div>
      <div class="detail-sidebar">
        ${tpTypeRow}
        <div style="font-size:28px;font-weight:800;color:var(--pink);margin-bottom:5px" id="detailPrice">฿${fmt(c.price)}</div>
        ${c.seats?`<div style="font-size:12px;color:#f59e0b;margin-bottom:10px">⚠ Only ${c.seats} seats left!</div>`:""}
        ${enrolled?`<button style="width:100%;padding:12px;border-radius:12px;border:none;background:#d1fae5;color:#065f46;font-weight:600;font-size:14px;cursor:default;margin-bottom:9px">✓ Already Enrolled</button>`:`
          <button class="btn-primary" id="detailCartBtn" style="width:100%;padding:12px;border-radius:12px;font-size:14px;font-weight:600;margin-bottom:9px" onclick="detailAddCart()">Add to Cart</button>
          <button class="btn-outline" style="width:100%;padding:12px;border-radius:12px;font-size:14px;font-weight:600;margin-bottom:9px" onclick="detailAddCart();showPage('cart')">Buy Now</button>
        `}
        <div style="font-size:11px;color:var(--text2);text-align:center;margin-bottom:13px">30-day money-back guarantee</div>
        <div style="border-top:1px solid var(--border);padding-top:12px">
          ${[["⏱","Duration",c.duration],["🎬","Content",c.hours+" hrs"],["📊","Level",c.level],["🌐","Format",c.type==="online"?"Online":"Onsite"]].map(([ic,label,val])=>`<div style="display:flex;justify-content:space-between;font-size:12px;padding:4px 0;color:var(--text2)"><span>${ic} ${label}</span><span style="font-weight:500;color:var(--text)">${val}</span></div>`).join("")}
        </div>
