}
function switchDetailType(type){
  if(!activeCourse||!activeCourse._tp)return;
  activeCourse.type=type;
  activeCourse.price=type==="onsite"?activeCourse.priceOnsite:activeCourse.priceOnline;
  document.getElementById("detailPrice").textContent="฿"+fmt(activeCourse.price);
  document.getElementById("detailTypeBadge").className="badge "+(type==="onsite"?"badge-onsite":"badge-online");
  document.getElementById("detailTypeBadge").textContent=type==="onsite"?"🏫 Onsite":"🎬 Online";
  document.getElementById("dt-onsite").className="sel-onsite"+(type==="onsite"?" selected":"");
  document.getElementById("dt-online").className="sel-online"+(type==="online"?" selected":"");
  courseTypeChoice[activeCourse.id]=type;
}
function detailAddCart(){
  const c=activeCourse;
  if(c._tp)addToCart(c.id,c.type,c.price,c.title,c.thumb,c.instructor);
  else addFlatToCart(c);
}
function playVideo(){
  const c=activeCourse;
  if(!c.vid){showToast("Preview not available for this course","#f59e0b");return;}
  const box=document.getElementById("videoBox");
  box.innerHTML=`<iframe src="${c.vid}" style="width:100%;height:100%;border:none" allowfullscreen></iframe>`;
  box.style.cursor="default";
}

// ── CART ──────────────────────────────────────────────────────────────────────
let cartStep="cart",cartDiscount=0;
function renderCart(){
  const el=document.getElementById("cartContent");
  if(cart.length===0){
    el.innerHTML=`<div class="empty-box"><div class="empty-icon">🛒</div><h2 style="margin-bottom:11px">Your cart is empty</h2><button class="btn-primary" onclick="showPage('training')" style="padding:11px 26px;border-radius:10px">Browse Courses</button></div>`;return;
  }
  const sub=cart.reduce((a,c)=>a+c.price,0);
  const total=sub-cartDiscount;
  const itemsHTML=cart.map(c=>`<div class="cart-item">
    <div class="cart-thumb">${c.thumb}</div>
    <div style="flex:1">
      <div style="font-weight:600;font-size:13px">${c.title}</div>
      <div style="font-size:11px;color:var(--text2);margin-top:2px">${c.instructor} · <span class="badge ${c.type==="onsite"?"badge-onsite":"badge-online"}">${c.type}</span></div>
    </div>
    <div style="text-align:right">
      <div style="font-weight:700;color:var(--pink);font-size:15px">฿${fmt(c.price)}</div>
      <button onclick="removeFromCart('${c.cartId}')" style="font-size:11px;color:#ef4444;background:none;border:none;cursor:pointer;margin-top:3px">Remove</button>
    </div>
  </div>`).join("");
  const payHTML=`<div style="background:#fff;border:1px solid var(--border);border-radius:16px;padding:20px">
    <div style="font-weight:600;font-size:14px;margin-bottom:12px">💳 Pay with Card</div>
    <label class="form-label">Card Number</label><input class="form-input" id="cardNum" placeholder="1234 5678 9012 3456"/>
    <label class="form-label">Cardholder Name</label><input class="form-input" id="cardName" placeholder="Your Name"/>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:11px">
      <div><label class="form-label">Expiry</label><input class="form-input" id="cardExp" placeholder="MM/YY"/></div>
      <div><label class="form-label">CVV</label><input class="form-input" id="cardCvv" placeholder="123"/></div>
    </div>
    <div style="font-size:11px;color:var(--text2);margin-top:5px">🔒 Secured by Stripe (Test Mode)</div>
  </div>`;
  el.innerHTML=`<h1 style="font-size:24px;font-weight:700;margin-bottom:20px">Your Cart (${cart.length} items)</h1>
    <div class="step-indicator">
      <button class="${cartStep==="cart"?"active-step":""}" onclick="setCartStep('cart')">🛒 Cart</button>
      <button class="${cartStep==="pay"?"active-step":""}" onclick="setCartStep('pay')">💳 Payment</button>
    </div>
    <div class="cart-grid">
      <div>${cartStep==="cart"?itemsHTML:payHTML}</div>
      <div class="summary-box">
        <div style="font-weight:600;font-size:14px;margin-bottom:12px">Order Summary</div>
        <div class="summary-row"><span>Subtotal</span><span>฿${fmt(sub)}</span></div>
        ${cartDiscount>0?`<div class="summary-row" style="color:#10b981"><span>Discount</span><span>-฿${fmt(cartDiscount)}</span></div>`:""}
        <div class="summary-total"><span>Total</span><span style="color:var(--pink)">฿${fmt(total)}</span></div>
        ${cartStep==="cart"?`<div class="promo-row">
          <input id="promoInput" placeholder="Promo code"/>
          <button class="btn-outline" style="padding:8px 12px;white-space:nowrap" onclick="applyPromo()">Apply</button>
        </div>
        <button class="btn-primary" style="width:100%;padding:12px;border-radius:12px;font-size:14px;font-weight:600;margin-top:5px" onclick="setCartStep('pay')">Proceed to Checkout</button>`
        :`<button class="btn-primary" style="width:100%;padding:12px;border-radius:12px;font-size:14px;font-weight:600;margin-top:10px" id="payBtn" onclick="processPay()">Pay Now ฿${fmt(total)}</button>
         <button class="btn-outline" style="width:100%;padding:9px;border-radius:10px;margin-top:7px;font-size:12px" onclick="setCartStep('cart')">← Back</button>`}
      </div>
    </div>`;
}
function setCartStep(s){cartStep=s;renderCart();}
function applyPromo(){
  const code=document.getElementById("promoInput")?.value.toUpperCase();
  const sub=cart.reduce((a,c)=>a+c.price,0);
  if(code==="NEWYEAR30"){cartDiscount=Math.round(sub*.3);showToast("30% discount applied! 🎉");}
  else if(code==="ONLINE25"){cartDiscount=Math.round(sub*.25);showToast("25% discount applied! 🎉");}
  else if(code==="CORP20"){cartDiscount=Math.round(sub*.2);showToast("20% discount applied! 🎉");}
  else{showToast("Invalid promo code","#ef4444");return;}
  renderCart();
}
function processPay(){
  const btn=document.getElementById("payBtn");
  btn.textContent="Processing…";btn.disabled=true;btn.style.background="#9ca3af";
  setTimeout(()=>{
    const newIds=cart.map(c=>c.id);
    if(currentUser){
      newIds.forEach(id=>{if(!currentUser.enrolled.includes(id))currentUser.enrolled.push(id);currentUser.progress[id]=currentUser.progress[id]||0;});
      enrolledIds=[...currentUser.enrolled];userProgress={...currentUser.progress};
    }
    cart=[];cartDiscount=0;cartStep="cart";updateCartBadge();
    document.getElementById("cartContent").innerHTML=`<div class="success-box"><div class="success-icon">🎉</div><h2 style="font-size:24px;font-weight:700;margin-bottom:7px">Payment Successful!</h2><p style="color:var(--text2);margin-bottom:22px">You now have access to your courses.</p><button class="btn-primary" style="padding:12px 28px;border-radius:12px;font-size:14px;font-weight:600" onclick="showPage('dashboard')">Go to My Courses</button></div>`;
  },2000);
}

// ── DASHBOARD ─────────────────────────────────────────────────────────────────
function renderDashboard(){
  const el=document.getElementById("dashContent");
  if(!currentUser){el.innerHTML=`<div class="empty-box"><div class="empty-icon">🔐</div><h2 style="margin-bottom:14px">Sign in to view your courses</h2><button class="btn-primary" onclick="openAuth('signin')" style="padding:11px 26px;border-radius:10px">Sign In</button></div>`;return;}
  // collect all enrolled courses (flat + product)
  const allCourses=[];
  enrolledIds.forEach(id=>{
    const flat=COURSES.find(c=>c.id===id);
    if(flat){allCourses.push({id:flat.id,title:flat.title,thumb:flat.thumb,instructor:flat.instructor});return;}
    PRODUCTS.forEach(p=>{const tc=p.courses.find(c=>c.id===id);if(tc)allCourses.push({id:tc.id,title:tc.title,thumb:tc.thumb,instructor:tc.instructor});});
  });
  el.innerHTML=`<div class="dash-welcome">
    <div class="dash-avatar">${currentUser.name[0].toUpperCase()}</div>
    <div><div style="font-weight:700;font-size:19px">Welcome back, ${currentUser.name}!</div><div style="font-size:12px;color:var(--text2)">${allCourses.length} courses enrolled</div></div>
  </div>
  <div style="font-size:20px;font-weight:700;margin-bottom:16px">My Courses</div>
  ${allCourses.length===0?`<div class="empty-box"><div class="empty-icon">📚</div><p style="color:var(--text2);margin-bottom:12px">No courses yet.</p><button class="btn-primary" onclick="showPage('training')" style="padding:11px 22px;border-radius:10px">Browse Courses</button></div>`
  :`<div class="card-grid">${allCourses.map(c=>{
    const pct=userProgress[c.id]||0;
    return `<div style="background:#fff;border:1px solid var(--border);border-radius:var(--radius-lg);overflow:hidden">
      <div style="height:80px;background:linear-gradient(135deg,var(--pink-light),var(--purple-light));display:flex;align-items:center;justify-content:center;font-size:36px">${c.thumb}</div>
      <div style="padding:13px">
        <div style="font-weight:600;font-size:13px;margin-bottom:3px;line-height:1.3">${c.title}</div>
        <div style="font-size:11px;color:var(--text2);margin-bottom:9px">${c.instructor}</div>
        <div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:3px"><span style="color:var(--text2)">Progress</span><span style="font-weight:500;color:${pct>=100?"#10b981":"var(--pink)"}">${pct}%</span></div>
        <div class="prog-bar"><div class="prog-fill ${pct>=100?"complete":""}" style="width:${pct}%"></div></div>
        ${pct>=100?`<button style="width:100%;margin-top:9px;padding:7px;border-radius:7px;border:none;background:linear-gradient(135deg,#10b981,#059669);color:#fff;font-weight:500;cursor:pointer;font-size:12px">🏆 Get Certificate</button>`
        :`<button onclick="incrementProgress('${c.id}')" style="width:100%;margin-top:9px;padding:7px;border-radius:7px;border:none;background:linear-gradient(135deg,var(--pink),var(--pink2));color:#fff;font-weight:500;cursor:pointer;font-size:12px">${pct>0?"Continue →":"Start Now →"}</button>`}
      </div>
    </div>`;
  }).join("")}</div>`}`;
}
function incrementProgress(id){
  userProgress[id]=Math.min(100,(userProgress[id]||0)+15);
  if(currentUser)currentUser.progress[id]=userProgress[id];
  renderDashboard();
  if(userProgress[id]>=100)showToast("Course completed! 🏆🎉");
}

