let adminCourses=[...COURSES],adminTab="overview",editingId=null;
function renderAdmin(){
  const el=document.getElementById("adminContent");
  const totalRev=adminCourses.reduce((a,c)=>a+c.price*c.students,0);
  const totalEnroll=adminCourses.reduce((a,c)=>a+c.students,0);
  const tabsHTML=`<div class="admin-tabs">${["overview","courses","users"].map(t=>`<button class="admin-tab${adminTab===t?" active":""}" onclick="setAdminTab('${t}')">${t.charAt(0).toUpperCase()+t.slice(1)}</button>`).join("")}</div>`;
  let content="";
  if(adminTab==="overview"){
    content=`<div class="admin-stat-grid">
      <div class="admin-stat"><div style="font-size:26px">📚</div><div class="admin-stat-num">${adminCourses.length}</div><div class="admin-stat-label">Courses</div></div>
